  1	import React, { cloneElement, FC } from 'react';
  2	
  3	import {
  4	  ChartLabel,
  5	  ChartLegend,
  6	  ChartLegendTooltipContentProps,
  7	  ChartLegendTooltipLabel,
  8	  getTheme,
  9	} from '@patternfly/react-charts/victory';
 10	import { ChartLegendTooltipStyles } from '@patternfly/react-charts/dist/esm/components/ChartTheme/ChartStyles';
 11	import {
 12	  getLegendTooltipDataProps,
 13	  getLegendTooltipSize,
 14	  getLegendTooltipVisibleData,
 15	  getLegendTooltipVisibleText,
 16	} from '@patternfly/react-charts/dist/esm/components/ChartUtils/chart-tooltip';
 17	
 18	import { evaluateProp } from '../utils/utils';
 19	
 20	const ChartLegendTooltipContent: FC<
 21	  ChartLegendTooltipContentProps & {
 22	    mainDataName?: string;
 23	    stack?: boolean;
 24	  }
 25	> = (props) => {
 26	  const {
 27	    activePoints,
 28	    center,
 29	    dx = 0,
 30	    dy = 0,
 31	    flyoutHeight,
 32	    flyoutWidth,
 33	    height,
 34	    labelComponent = <ChartLegendTooltipLabel />,
 35	    legendComponent = <ChartLegend />,
 36	    legendData,
 37	    mainDataName,
 38	    stack,
 39	    text,
 40	    themeColor,
 41	    title,
 42	    titleComponent = <ChartLabel />,
 43	    width,
 44	    // destructure last
 45	    // eslint-disable-next-line perfectionist/sort-objects
 46	    theme = getTheme(themeColor),
 47	    ...rest
 48	  } = props;
 49	  const pointerLength = theme?.tooltip ? evaluateProp(theme.tooltip.pointerLength, props) : 10;
 50	  const legendProps = getLegendTooltipDataProps(legendComponent.props);
 51	  const visibleLegendData = getLegendTooltipVisibleData({
 52	    activePoints,
 53	    colorScale: legendProps.colorScale,
 54	    legendData,
 55	    text,
 56	    theme,
 57	  });
 58	
 59	  const hasMainData = mainDataName ? activePoints[0].childName === mainDataName : false;
 60	
 61	  if (stack) {
 62	    visibleLegendData.reverse();
 63	  } else if (hasMainData) {
 64	    visibleLegendData.shift();
 65	  }
 66	
 67	  // Component offsets
 68	  const legendOffsetX = 0;
 69	  const legendOffsetY = title ? 9 : -10;
 70	  const titleOffsetX = 10;
 71	  const titleOffsetY = 0;
 72	
 73	  // Returns x position of flyout
 74	  const getX = () => {
 75	    if (!(center || flyoutWidth || width)) {
 76	      const x = (rest as any).x;
 77	      return x ? x : undefined;
 78	    }
 79	    const _flyoutWidth = evaluateProp(flyoutWidth, props);
 80	    if (width > center.x + _flyoutWidth + pointerLength) {
 81	      return center.x + ChartLegendTooltipStyles.flyout.padding / 2;
 82	    } else if (center.x < _flyoutWidth + pointerLength) {
 83	      return ChartLegendTooltipStyles.flyout.padding / 2 - pointerLength;
 84	    }
 85	    return center.x - _flyoutWidth;
 86	  };
 87	
 88	  // Returns y position
 89	  const getY = () => {
 90	    if (!(center || flyoutHeight || height)) {
 91	      const y = (rest as any).y;
 92	      return y ? y : undefined;
 93	    }
 94	    const _flyoutHeight = evaluateProp(flyoutHeight, props);
 95	    if (center.y < _flyoutHeight / 2) {
 96	      return ChartLegendTooltipStyles.flyout.padding / 2;
 97	    } else if (center.y > height - _flyoutHeight / 2) {
 98	      return height - _flyoutHeight + ChartLegendTooltipStyles.flyout.padding / 2;
 99	    }
100	    return center.y - _flyoutHeight / 2 + ChartLegendTooltipStyles.flyout.padding / 2;
101	  };
102	
103	  // Min & max dimensions do not include flyout padding
104	  const maxLegendDimensions = getLegendTooltipSize({
105	    legendData: visibleLegendData,
106	    legendProps,
107	    text: getLegendTooltipVisibleText({ activePoints, legendData, text }),
108	    theme,
109	  });
110	  const minLegendDimensions = getLegendTooltipSize({
111	    legendData: [{ name: '' }],
112	    legendProps,
113	    theme,
114	  });
115	
116	  // Returns the label component
117	  const getLabelComponent = () =>
118	    cloneElement(labelComponent, {
119	      dx: maxLegendDimensions.width - minLegendDimensions.width,
120	      legendData: visibleLegendData,
121	      ...labelComponent.props,
122	    });
123	
124	  // Returns the title component
125	  const getTitleComponent = () => {
126	    const _title = title instanceof Function ? title(activePoints) : title;
127	
128	    return cloneElement(titleComponent, {
129	      style: {
130	        fill: ChartLegendTooltipStyles.label.fill,
131	      },
132	      text: _title,
133	      textAnchor: 'start',
134	      x: getX() + titleOffsetX + evaluateProp(dx, props),
135	      y: getY() + titleOffsetY + evaluateProp(dy, props),
136	      ...titleComponent.props,
137	    });
138	  };
139	
140	  const tooltipLegendData = getLegendTooltipVisibleData({
141	    activePoints,
142	    colorScale: legendProps.colorScale,
143	    legendData,
144	    text,
145	    textAsLegendData: true,
146	    theme,
147	  });
148	
149	  if (stack) {
150	    tooltipLegendData.reverse();
151	  } else if (hasMainData) {
152	    tooltipLegendData.shift();
153	  }
154	
155	  // Returns the legend component
156	  const getLegendComponent = () =>
157	    cloneElement(legendComponent, {
158	      data: tooltipLegendData,
159	      labelComponent: getLabelComponent(),
160	      standalone: false,
161	      theme,
162	      x: getX() + legendOffsetX + evaluateProp(dx, props),
163	      y: getY() + legendOffsetY + evaluateProp(dy, props),
164	      ...legendProps,
165	    });
166	
167	  return (
168	    <>
169	      {getTitleComponent()}
170	      {getLegendComponent()}
171	    </>
172	  );
173	};
174	
175	export default ChartLegendTooltipContent;

